import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { X, Send, Mic, Volume2, VolumeX, Loader2, Globe, ChevronDown, Square, Play, Pause } from 'lucide-react';
import { MenuItem, SocialPost, Language } from '../types';
import { generateSystemInstruction, generateSpeech } from '../services/geminiService';
import { WaiterAvatar } from './WaiterAvatar';

interface Props {
  menu: MenuItem[];
  posts: SocialPost[];
  language: Language;
  autoStart?: boolean;
}

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  audioUrl?: string;
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Audio Helper Function
async function decodeAudioData(audioData: ArrayBuffer, sampleRate: number = 24000): Promise<AudioBuffer> {
  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate });

  // Create a view of the ArrayBuffer
  const dataView = new DataView(audioData);

  // Since Gemini TTS returns raw PCM (linear 16-bit little-endian), we need to manually decode it
  const numChannels = 1;
  const numSamples = audioData.byteLength / 2; // 16-bit = 2 bytes
  const buffer = audioContext.createBuffer(numChannels, numSamples, sampleRate);
  const channelData = buffer.getChannelData(0);

  for (let i = 0; i < numSamples; i++) {
     // Convert 16-bit integer to float [-1.0, 1.0]
     const int16 = dataView.getInt16(i * 2, true);
     channelData[i] = int16 / 32768.0;
  }

  return buffer;
}

// Blob to Base64 Helper
const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

const getSupportedMimeType = () => {
  const types = [
    'audio/webm;codecs=opus',
    'audio/webm',
    'audio/mp4',
    'audio/ogg'
  ];
  for (const type of types) {
    if (MediaRecorder.isTypeSupported(type)) return type;
  }
  return ''; // Let browser choose default
};

const getGreeting = (lang: Language): string => {
    switch (lang) {
        case 'de': return "Bonjour! Ich bin Pierre, Ihr Kellner. Wie kann ich Ihnen behilflich sein?";
        case 'fr': return "Bonjour ! Je suis Pierre, votre serveur. Comment puis-je vous aider ?";
        case 'it': return "Bonjour! Sono Pierre, il vostro cameriere. Come posso aiutarvi?";
        case 'tr': return "Bonjour! Ben Pierre, garsonunuz. Size nasıl yardımcı olabilirim?";
        case 'en': 
        default: return "Bonjour! I am Pierre, your waiter. How can I help you today?";
    }
};

const getFallbackText = (lang: Language): string => {
   switch(lang) {
     case 'en': return "I apologize, I didn't catch that.";
     case 'fr': return "Je m'excuse, je n'ai pas compris.";
     case 'it': return "Mi scuso, non ho capito.";
     case 'tr': return "Özür dilerim, anlayamadım.";
     case 'de':
     default: return "Entschuldigung, ich habe das nicht verstanden.";
   }
};

const getInputPlaceholder = (lang: Language): string => {
    switch(lang) {
        case 'de': return "Fragen Sie den Kellner...";
        case 'fr': return "Demandez au serveur...";
        case 'it': return "Chiedi al cameriere...";
        case 'tr': return "Garsona sor...";
        case 'en': 
        default: return "Ask the waiter...";
    }
};

export const ChatBot: React.FC<Props> = ({ menu, posts, language, autoStart = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [chatLanguage, setChatLanguage] = useState<Language>(language);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSoundOn, setIsSoundOn] = useState(false);

  // Recording State
  const [isRecording, setIsRecording] = useState(false);

  const [isSpeaking, setIsSpeaking] = useState(false);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const hasAutoStartedRef = useRef(false);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingMimeTypeRef = useRef<string>('');

  // Use a ref to track sound preference for access inside async callbacks (closures)
  const isSoundOnRef = useRef(isSoundOn);

  // Sync chat language with global language on mount or prop change, 
  // but allow user to override it locally in chat.
  useEffect(() => {
    setChatLanguage(language);
  }, [language]);

  // Sync isSoundOn state to Ref
  useEffect(() => {
    isSoundOnRef.current = isSoundOn;
  }, [isSoundOn]);

  // Initialize Chat Session with History Preservation
  // We recreate the session whenever the config (language/menu) changes
  useEffect(() => {
    if (isOpen) {
      // Preserve history when switching languages to keep context
      // Note: We only keep text parts for history reconstruction to avoid large payloads
      const history = messages
        .filter(m => m.id !== 'init') 
        .map(m => ({
            role: m.role,
            parts: [{ text: m.text }] 
        }));

      chatSessionRef.current = ai.chats.create({
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction: generateSystemInstruction(menu, posts, chatLanguage),
        },
        history: history
      });
    }
  }, [isOpen, menu, posts, chatLanguage]); 

  // Handle Greeting Logic (Initial Open or Language Switch)
  useEffect(() => {
    if (isOpen) {
        const greetingText = getGreeting(chatLanguage);

        const isInitOnly = messages.length === 0 || (messages.length === 1 && messages[0].id === 'init');

        if (isInitOnly) {
             if (messages.length === 0 || messages[0].text !== greetingText) {
                 setMessages([{ id: 'init', role: 'model', text: greetingText }]);

                 if (isSoundOn) {
                    setTimeout(() => {
                        if (isSoundOnRef.current) {
                            playResponseAudio(greetingText);
                        }
                    }, 500);
                 }
             }
        }
    }
  }, [isOpen, chatLanguage]);

  // Handle Auto Start (Sound on Open)
  useEffect(() => {
    if (autoStart && !hasAutoStartedRef.current) {
        setIsOpen(true);
        setIsSoundOn(true);
        hasAutoStartedRef.current = true;
    }
  }, [autoStart]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const toggleSound = () => {
      const newState = !isSoundOn;
      setIsSoundOn(newState);

      // If turning off, stop any current audio
      if (!newState && currentSourceRef.current) {
          try {
              currentSourceRef.current.stop();
              currentSourceRef.current = null;
              setIsSpeaking(false);
          } catch (e) {
              // Ignore error if already stopped
          }
      }
  };

  const handleSend = async (text: string = input, audioBase64?: string, audioMimeType?: string) => {
    if ((!text.trim() && !audioBase64) || !chatSessionRef.current) return;

    // Add user message to UI
    const userMsg: Message = { 
        id: Date.now().toString(), 
        role: 'user', 
        text: text || (audioBase64 ? "🎤 Voice Message" : ""),
        audioUrl: undefined // Will be handled by the caller for local blob url
    };

    // If called from text input
    if (text) {
        setMessages(prev => [...prev, userMsg]);
        setInput('');
    } 
    // If called from audio recording, the caller handles adding the message with audioUrl

    setIsLoading(true);

    try {
      let result: GenerateContentResponse;

      if (audioBase64 && audioMimeType) {
          // Send audio part
          result = await chatSessionRef.current.sendMessage({
              message: {
                  parts: [
                      {
                          inlineData: {
                              mimeType: audioMimeType,
                              data: audioBase64
                          }
                      }
                  ]
              }
          });
      } else {
          // Send text part
          result = await chatSessionRef.current.sendMessage({ message: text });
      }

      const responseText = result.text || getFallbackText(chatLanguage);

      const botMsg: Message = { id: (Date.now() + 1).toString(), role: 'model', text: responseText };
      setMessages(prev => [...prev, botMsg]);

      if (isSoundOnRef.current) {
        await playResponseAudio(responseText);
      }
    } catch (error) {
      console.error("Chat Error", error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "Connection error / Verbindungsfehler" }]);
    } finally {
      setIsLoading(false);
    }
  };

  const playResponseAudio = async (text: string) => {
    try {
        if (currentSourceRef.current) {
            try {
                currentSourceRef.current.stop();
            } catch (e) {}
            currentSourceRef.current = null;
        }

        setIsSpeaking(true);
        const audioBufferData = await generateSpeech(text);

        if (audioBufferData) {
            if (!audioContextRef.current) {
                audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            }
            const ctx = audioContextRef.current;

            if (ctx.state === 'suspended') {
                await ctx.resume();
            }

            const audioBuffer = await decodeAudioData(audioBufferData);
            const source = ctx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(ctx.destination);

            source.onended = () => {
                setIsSpeaking(false);
                currentSourceRef.current = null;
            };

            currentSourceRef.current = source;
            source.start(0);
        } else {
            setIsSpeaking(false);
        }
    } catch (e) {
        console.error("Audio Playback Error", e);
        setIsSpeaking(false);
    }
  };

  const startRecording = async () => {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        const mimeType = getSupportedMimeType();
        const options = mimeType ? { mimeType } : undefined;
        recordingMimeTypeRef.current = mimeType;

        const mediaRecorder = new MediaRecorder(stream, options);
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (event) => {
            if (event.data.size > 0) {
                audioChunksRef.current.push(event.data);
            }
        };

        mediaRecorder.onstop = async () => {
             // Use the actual mime type of the recorder if available, or fall back to the requested one, or generic
             const finalMimeType = mediaRecorder.mimeType || recordingMimeTypeRef.current || 'audio/webm';
             const audioBlob = new Blob(audioChunksRef.current, { type: finalMimeType });

             // Create URL for playback
             const audioUrl = URL.createObjectURL(audioBlob);

             // Convert to base64 for API
             try {
                 const base64 = await blobToBase64(audioBlob);

                 // Add User Message with Audio
                 const userMsg: Message = { 
                    id: Date.now().toString(), 
                    role: 'user', 
                    text: "🎤 Voice Message",
                    audioUrl: audioUrl
                 };
                 setMessages(prev => [...prev, userMsg]);

                 // Send to Gemini
                 await handleSend("", base64, finalMimeType);
             } catch (e) {
                 console.error("Audio conversion failed", e);
             }

             // Stop tracks
             stream.getTracks().forEach(track => track.stop());
        };

        mediaRecorder.start();
        setIsRecording(true);

        // Stop any bot speech if recording starts
        if (currentSourceRef.current) {
            try {
                currentSourceRef.current.stop();
                setIsSpeaking(false);
            } catch(e) {}
        }

    } catch (e) {
        console.error("Could not start recording", e);
        alert("Mikrofonzugriff verweigert oder nicht verfügbar. Bitte prüfen Sie Ihre Einstellungen.");
    }
  };

  const stopRecording = () => {
      if (mediaRecorderRef.current && isRecording) {
          mediaRecorderRef.current.stop();
          setIsRecording(false);
      }
  };

  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      setChatLanguage(e.target.value as Language);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 w-16 h-16 bg-[#003399] text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 transition-transform z-50 border-4 border-slate-900 overflow-hidden"
      >
        <WaiterAvatar className="w-12 h-12" />
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-[90vw] md:w-96 h-[500px] bg-slate-900 rounded-2xl shadow-2xl flex flex-col z-50 overflow-hidden border border-slate-700 animate-in slide-in-from-bottom-10 fade-in duration-300">

      {/* Header */}
      <div className="bg-[#003399] p-4 flex justify-between items-center text-white">
        <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center overflow-hidden border-2 transition-all ${isSpeaking ? 'border-green-400 shadow-[0_0_10px_rgba(74,222,128,0.5)] scale-105' : 'border-blue-200'}`}>
                <WaiterAvatar className="w-8 h-8 mt-1" />
            </div>
            <div>
                <h3 className="font-bold text-sm">Rheinhafen Kellner</h3>
                <span className="text-xs text-blue-200 flex items-center gap-1">
                    <span className={`w-2 h-2 rounded-full ${isSpeaking ? 'bg-green-400 animate-pulse' : 'bg-green-400/50'}`}></span>
                    {isSpeaking ? 'Spricht...' : 'Online'}
                </span>
            </div>
        </div>
        <div className="flex items-center gap-2">
            {/* Language Dropdown */}
            <div className="relative group flex items-center bg-blue-800/50 rounded-full pl-3 pr-2 py-1.5 border border-blue-700 cursor-pointer hover:bg-blue-700/50 transition-colors" title="Sprache & Stimme / Language & Voice">
                <Globe size={14} className="text-blue-200 mr-2" />
                <div className="relative">
                    <select 
                        value={chatLanguage} 
                        onChange={handleLanguageChange}
                        className="bg-transparent text-xs font-bold text-white outline-none cursor-pointer appearance-none pr-5 py-0.5 w-full z-10 relative"
                    >
                        <option value="de" className="bg-slate-900">🇩🇪 Deutsch</option>
                        <option value="en" className="bg-slate-900">🇬🇧 English</option>
                        <option value="fr" className="bg-slate-900">🇫🇷 Français</option>
                        <option value="it" className="bg-slate-900">🇮🇹 Italiano</option>
                        <option value="tr" className="bg-slate-900">🇹🇷 Türkçe</option>
                    </select>
                    <ChevronDown size={12} className="text-blue-300 absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none z-0" />
                </div>
            </div>

            <div className="flex flex-col items-center mr-1">
                <button 
                    onClick={toggleSound} 
                    className={`p-2 rounded-full transition-colors border ${isSoundOn ? 'bg-green-500/20 text-green-100 border-green-500/50 shadow-inner' : 'text-white/40 border-transparent hover:text-white hover:bg-white/10'}`}
                    title={isSoundOn ? "Sprachausgabe ausschalten" : "Sprachausgabe einschalten"}
                >
                    {isSoundOn ? <Volume2 size={18} /> : <VolumeX size={18} />}
                </button>
            </div>
            <button onClick={() => setIsOpen(false)} className="p-2 rounded-full hover:bg-white/10">
                <X size={20} />
            </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-950">
        {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                {msg.role === 'model' && (
                    <div className="w-8 h-8 rounded-full bg-slate-100 border border-slate-700 flex items-center justify-center overflow-hidden mr-2 flex-shrink-0">
                         <WaiterAvatar className="w-6 h-6 mt-1" />
                    </div>
                )}
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm flex flex-col gap-2 ${
                    msg.role === 'user' 
                    ? 'bg-[#003399] text-white rounded-tr-none' 
                    : 'bg-slate-800 text-slate-100 shadow-sm border border-slate-700 rounded-tl-none'
                }`}>
                    {msg.text && <span>{msg.text}</span>}

                    {msg.audioUrl && (
                        <audio controls src={msg.audioUrl} className="h-8 w-48 mt-1 rounded opacity-90" />
                    )}
                </div>
            </div>
        ))}
        {isLoading && (
            <div className="flex justify-start">
                 <div className="w-8 h-8 rounded-full bg-slate-100 border border-slate-700 flex items-center justify-center overflow-hidden mr-2 flex-shrink-0">
                         <WaiterAvatar className="w-6 h-6 mt-1" />
                    </div>
                <div className="bg-slate-800 p-3 rounded-2xl rounded-tl-none shadow-sm border border-slate-700 flex items-center gap-2">
                    <Loader2 className="w-4 h-4 animate-spin text-blue-400" />
                    <span className="text-xs text-slate-400">...</span>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-3 bg-slate-900 border-t border-slate-700 flex items-center gap-2">
        <button 
            onClick={isRecording ? stopRecording : startRecording}
            className={`p-3 rounded-full transition-all duration-300 relative ${
                isRecording 
                ? 'bg-red-900/50 text-red-500 scale-110 shadow-[0_0_15px_rgba(239,68,68,0.5)]' 
                : 'bg-slate-800 text-slate-400 hover:bg-slate-700'
            }`}
            title={isRecording ? "Aufnahme stoppen" : "Sprachnachricht aufnehmen"}
        >
            {isRecording ? (
                <>
                    <Square size={20} fill="currentColor" />
                    <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full animate-ping"></span>
                </>
            ) : (
                <Mic size={20} />
            )}
        </button>

        <div className="flex-1 relative">
             <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                disabled={isRecording}
                placeholder={isRecording ? "Aufnahme läuft..." : getInputPlaceholder(chatLanguage)}
                className={`w-full bg-slate-800 border border-slate-700 rounded-full px-4 py-2 text-sm text-white outline-none focus:border-[#003399] focus:ring-1 focus:ring-[#003399] placeholder-slate-500 transition-colors ${isRecording ? 'border-red-500/50 placeholder-red-400/70' : ''}`}
            />
        </div>

        <button 
            onClick={() => handleSend()}
            disabled={!input.trim() || isLoading || isRecording}
            className="p-3 bg-[#003399] text-white rounded-full hover:bg-[#002266] disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
            <Send size={18} />
        </button>
      </div>
    </div>
  );
};

