  const handleSpecificAutoTranslate = async (targetLang: Language) => {
    if (!editingItem) return;

    setTranslatingStates(prev => ({ ...prev, [targetLang]: true }));
    try {
        // Force refresh to ignore existing partial translations or cache
        const translation = await translateMenuItem(editingItem, targetLang, true);

        // Single atomic update
        setEditingItem(prev => {
            if (!prev) return null;
            return {
                ...prev,
                translations: {
                    ...prev.translations,
                    [targetLang]: {
                        ...(prev.translations?.[targetLang] || { name: '', description: '' }),
                        name: translation.name,
                        description: translation.description
                    }
                }
            };
        });
    } catch (error) {
        console.error("Translation failed", error);
    } finally {
        setTranslatingStates(prev => ({ ...prev, [targetLang]: false }));
    }
  };

  const handleNewItemAutoTranslate = async (targetLangOverride?: Language) => {
    const target = targetLangOverride;
    if (!newItem.name || !target || target === 'de') return;

    setNewItemTranslatingStates(prev => ({ ...prev, [target]: true }));
    try {
        const tempItem: MenuItem = {
            id: 'temp',
            name: newItem.name,
            description: newItem.description || '',
            price: newItem.price || 0,
            category: newItem.category || Category.MAIN,
            available: true
        };

        const translation = await translateMenuItem(tempItem, target, true);

        // Single atomic update
        setNewItem(prev => ({
            ...prev,
            translations: {
                ...prev.translations,
                [target]: {
                    ...(prev.translations?.[target] || { name: '', description: '' }),
                    name: translation.name,
                    description: translation.description
                }
            }
        }));
    } catch (error) {
        console.error("Translation failed", error);
    } finally {
        setNewItemTranslatingStates(prev => ({ ...prev, [target]: false }));
    }
