  const handleTranslateNameAll = async (target: 'new' | 'edit') => {
    const sourceItem = target === 'new' ? newItem : editingItem;
    if (!sourceItem || !sourceItem.name) return;

    setIsTranslatingName(true);
    const languages: Language[] = ['en', 'fr', 'it', 'tr'];

    try {
        const results = await Promise.all(
            languages.map(async (lang) => {
                // Create a temp item with available context. 
                // We use description if present to help the AI context, 
                // but we only extract and use the name from the result.
                const tempItem = { 
                    ...sourceItem, 
                    id: 'temp', 
                    price: sourceItem.price || 0, 
                    category: sourceItem.category || Category.MAIN, 
                    available: true,
                    description: sourceItem.description || '' 
                } as MenuItem;

                const translation = await translateMenuItem(tempItem, lang, true);
                return { lang, name: translation.name };
            })
        );

        if (target === 'new') {
            setNewItem(prev => {
                const newTranslations = { ...prev.translations };
                results.forEach(res => {
                    newTranslations[res.lang] = {
                        ...(newTranslations[res.lang] || { name: '', description: '' }),
                        name: res.name
                    };
                });
                return { ...prev, translations: newTranslations };
            });
        } else {
             setEditingItem(prev => {
                if (!prev) return null;
                const newTranslations = { ...prev.translations };
                results.forEach(res => {
                    newTranslations[res.lang] = {
                        ...(newTranslations[res.lang] || { name: '', description: '' }),
                        name: res.name
                    };
                });
                return { ...prev, translations: newTranslations };
            });
        }

    } catch (e) {
        console.error("Name batch translation failed", e);
    } finally {
        setIsTranslatingName(false);
    }
  };

