  const [newPostImage, setNewPostImage] = useState<string | null>(null);

  // Camera State - Persist to localStorage
  const [cameraUrl, setCameraUrl] = useState(() => {
    try {
      return localStorage.getItem('cameraUrl') || '';
    } catch (e) {
      console.warn("LocalStorage access failed", e);
      return '';
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem('cameraUrl', cameraUrl);
    } catch (e) {
      console.warn("LocalStorage write failed", e);
    }
  }, [cameraUrl]);

  const [isCameraConnected, setIsCameraConnected] = useState(false);
  const [cameraError, setCameraError] = useState<string | null>(null);

  // --- Sorting Logic ---
  const getSortedMenu = (items: MenuItem[]) => {
    return [...items].sort((a, b) => {
        let aValue: string | number = '';
        let bValue: string | number = '';

        switch (sortConfig.key) {
            case 'name':
                aValue = a.name.toLowerCase();
                bValue = b.name.toLowerCase();
                break;
            case 'price':
                aValue = a.price;
                bValue = b.price;
                break;
            case 'category':
                aValue = a.category;
                bValue = b.category;
                break;
        }

        if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
    });
  };

  // --- Category Logic ---
  const handleAddCategory = () => {
    const name = newCategoryName.trim();
    if (name && !categories.includes(name)) {
        setCategories([...categories, name]);
        setNewCategoryName('');
    }
  };

  const handleDeleteCategory = (categoryName: string) => {
    const hasItems = menu.some(item => item.category === categoryName);
    if (hasItems) {
