  // Refactored to allow targeting specific language with parallel loading states
  const handleSpecificAutoTranslate = async (targetLang: Language) => {
    if (!editingItem) return;

    setTranslatingStates(prev => ({ ...prev, [targetLang]: true }));
    try {
        // Force refresh to ignore existing partial translations or cache
        const translation = await translateMenuItem(editingItem, targetLang, true);

        // Single atomic update
        setEditingItem(prev => {
            if (!prev) return null;
            return {
                ...prev,
                translations: {
                    ...prev.translations,
                    [targetLang]: {
                        ...(prev.translations?.[targetLang] || { name: '', description: '' }),
                        name: translation.name,
                        description: translation.description
                    }
                }
            };
        });
    } catch (error) {
        console.error("Translation failed", error);
    } finally {
        setTranslatingStates(prev => ({ ...prev, [targetLang]: false }));
    }
  };

