        // Single atomic update
        setNewItem(prev => ({
            ...prev,
            translations: {
                ...prev.translations,
                [target]: {
                    ...(prev.translations?.[target] || { name: '', description: '' }),
                    name: translation.name,
                    description: translation.description
                }
            }
        }));
    } catch (error) {
        console.error("Translation failed", error);
    } finally {
        setNewItemTranslatingStates(prev => ({ ...prev, [target]: false }));
    }
