                            <div className="bg-slate-900 p-4 rounded-lg border border-slate-700 flex flex-col items-center gap-4 mt-4">
                                <h4 className="text-xs font-bold text-slate-500 uppercase">Vorschau</h4>
                                <div className="w-32 h-32 bg-white/5 rounded-full flex items-center justify-center border border-white/10 overflow-hidden">
                                    <Logo className="w-24 h-24" src={generatedLogoPreview || appLogo} />
                                </div>

                                {generatedLogoPreview && generatedLogoPreview !== appLogo && (
                                    <div className="flex gap-2 w-full">
                                        <button 
                                            onClick={handleSaveLogo}
                                            className="flex-1 bg-green-900/50 hover:bg-green-800 text-green-100 border border-green-700 py-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2"
                                        >
                                            <Save size={16} />
                                            Als App-Logo übernehmen
                                        </button>
                                        <button 
                                            onClick={() => setGeneratedLogoPreview(null)}
                                            className="px-4 py-2 bg-slate-800 text-slate-400 hover:text-white rounded-lg text-sm"
                                        >
                                            Verwerfen
                                        </button>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
             </div>
        )}

      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-blue-500 selection:text-white">
      {renderHeader()}

      <main className="flex-1 container mx-auto px-4 py-8 relative">
        {/* Staff Panel / Admin View */}
        {userMode === 'staff' && isAuthenticated && renderStaffPanel()}

        <div className="mb-8 relative max-w-md mx-auto">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Search className="h-5 w-5 text-slate-400" />
            </div>
            <input
                type="text"
                aria-label="Search dishes"
                className="block w-full pl-10 pr-10 py-3 border border-slate-700 rounded-full leading-5 bg-slate-900 text-slate-100 placeholder-slate-400 focus:outline-none focus:bg-slate-800 focus:border-[#003399] sm:text-sm transition-colors shadow-lg"
                placeholder={
                    language === 'de' ? 'Gericht nach Namen suchen...' :
                    language === 'fr' ? 'Rechercher un plat par nom...' :
                    language === 'it' ? 'Cerca piatto per nome...' :
                    language === 'tr' ? 'İsme göre yemek ara...' :
                    'Search dish by name...'
                }
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
            />
            {searchQuery && (
                <button 
                    onClick={() => setSearchQuery('')}
                    className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-white"
                >
                    <X className="h-5 w-5" />
                </button>
            )}
        </div>

        {/* Menu Section */}
        <div id="menu-section" className="space-y-16">
          {categories.map(category => renderMenuSection(category))}
        </div>

        {/* Social Feed Section (Only for customers or if no staff panel active, but usually visible to all at bottom) */}
        <div className="mt-20 border-t border-slate-800 pt-10">
          <h2 className="text-3xl font-bold text-center text-blue-400 mb-8 brand-font">Neues aus dem Rheinhafen</h2>
          <SocialFeed posts={posts} />
        </div>
      </main>

      <footer className="bg-slate-950 border-t border-slate-900 text-slate-400 py-8 mt-12">
        <div className="container mx-auto px-4 text-center">
          <div className="flex justify-center items-center gap-2 mb-4">
             <Anchor className="w-5 h-5 text-blue-500" />
             <span className="brand-font font-bold text-lg text-white">RHEINHAFEN</span>
          </div>
          <p className="mb-2">Hochbergerstrasse 160, 4057 Basel</p>
          <p className="text-sm opacity-60">&copy; {new Date().getFullYear()} Rheinhafen Restaurant. Alle Rechte vorbehalten.</p>
        </div>
      </footer>

      {/* Floating Elements */}
      <ChatBot menu={menu} posts={posts} language={language} autoStart={hasStarted} />

      <StaffLoginModal 
        isOpen={showLoginModal} 
        onClose={() => {
            setShowLoginModal(false);
            setUserMode('customer'); // Revert toggle if cancelled
        }}
        onLogin={handleLogin}
      />
    </div>
  );
}

